function [pvtXInd,pvtYInd,rotAngl,img] = fImgCntAnglV04(img,angle,osPrp,rawFrgT,rawFrgL,varargin)%% analyze image to get centroid and rotation angle% [pvtXInd,pvtYInd,rotAngl] = fImgCntAnglV04(img,angle,varargin)% cntX, cntY: centroid [pixel]% rotAngl: rotation angle [deg]% % img: input image% threshold: threshold% vergin: if any, output figure, %       {1}: rawFrgT%       {2}: rawFrgL%% Written by Kei Nakamura% 2016/1/6 ver.1: created% 2016/1/7 ver.2: output centroid and angle% 2016/1/25 ver.3: improve% 2016/1/27 ver.4: angle scan or no scan%%% used in% bellaFrogFirstAnlV04%% parametersrawImg = img;   % raw image[img(:,:),~] = fXrayOutV10(img,[1/4,3,1,2]);    % low pass[img(:,:),~] = fXrayOutV10(img,[1/4,2,1,2]);[img(:,:),~] = fXrayOutV10(img,[1/4,1,1,2]);img(:,:) = img.*(img>1);   % thresholding[sizeY,sizeX] = size(img);  % image size[~,pvtYInd] = min(abs(rawFrgL - 0.5*osPrp.lmb0));   % pivot y pixel[maxV,maxXInd] = max(max(img));  % pivot x pixelimg = img.*(img>maxV*0.1);  % threshold%disp([pvtXInd pvtXIndM])%% find pivot XxPrf = sum(img);    % integrate in yfor ii = 101:0.5*sizeX-1    rght = xPrf(ii+1:ii+0.5*sizeX); % right side    left = [fliplr(rght(ii+1:end)) xPrf(1:ii)];  % left side    rght = rght + fliplr(left); % symmetrize    rmsT(ii-100) = fGetRmsV01(1:0.5*sizeX,rght);    % rms of symmetrized profileendtemp = xPrf + fliplr(xPrf); % symmetrizermsM = fGetRmsV01(1:0.5*sizeX,temp(1:0.5*sizeX));xPrf = fliplr(xPrf);    % flip for other sidefor ii = 101:0.5*sizeX-1    rght = xPrf(ii+1:ii+0.5*sizeX); % right side    left = [fliplr(rght(ii+1:end)) xPrf(1:ii)];  % left side    rght = rght + fliplr(left); % symmetrize    rmsT2(ii-100) = fGetRmsV01(1:0.5*sizeX,rght);    % rms of symmetrized profileendrmsAll = [rmsT rmsM fliplr(rmsT2)];[~,minIdx] = min(rmsAll);pvtXInd = minIdx + 100;pvtXInd = round((pvtXInd + maxXInd)/2);pvtT = rawFrgT(pvtXInd);  % pivot timeif numel(angle)>1   % angle scan or static anlge    %% rotation scan to see    rotImg = img;   % allocation    xStd = angle;   % allocation    yStd = angle;   % allocation    peakP = angle;   % allocation    diffLR = angle; % allocation    for ii=1:numel(angle)        rotImg(:,:) = fImageRotV02(img,angle(ii),[pvtXInd,pvtYInd]);        [rotImg(:,:),diffLR(ii)] = fImageSymV01(rotImg,pvtXInd);   % symmetrize        rotImgX = sum(rotImg);  % x profile        rotImgY = sum(rotImg,2);  % x profile        [xStd(ii),~] = fGetRmsV01(1:sizeX,rotImgX);  % x-rms        [yStd(ii),~] = fGetRmsV01(1:sizeY,rotImgY');  % y-rms        peakP(ii) = max(rotImgX);    end    %% define angle based on min(diffLR)    [~,rotAnglInd] = min(diffLR);   % index    rotAngl = angle(rotAnglInd);    % rotation angle [deg]    a1 = tan(rotAngl*pi/180);   % y pixel/1 x pixel    a1C = a1 * (rawFrgL(2) - rawFrgL(1)) / (rawFrgT(2) - rawFrgT(1));   % slope in fs-nm    lin1 = fPa2Line([pvtT 0.5*osPrp.lmb0],a1C); % line 1    a2 = -tan((90-rotAngl)*pi/180);    a2C = a2 * (rawFrgL(2) - rawFrgL(1)) / (rawFrgT(2) - rawFrgT(1));   % slope in fs-nm    lin2 = fPa2Line([pvtT 0.5*osPrp.lmb0],a2C);    %% figure output    set(gca,'fontsize',14);    pcolor(rawFrgT,rawFrgL,rawImg)    shading interp    colormap jet    hold on    plot([-200 200],[fLineX2YV01(lin1,-200) fLineX2YV01(lin1,200)],'w-')    plot([-200 200],[fLineX2YV01(lin1,-200)+5 fLineX2YV01(lin1,200)+5],'w--')    plot([-200 200],[fLineX2YV01(lin1,-200)-5 fLineX2YV01(lin1,200)-5],'w--')    plot([-200 200],[fLineX2YV01(lin2,-200) fLineX2YV01(lin2,200)],'w-')    plot([-300 100],[fLineX2YV01(lin2,-200) fLineX2YV01(lin2,200)],'w-')    plot([-100 300],[fLineX2YV01(lin2,-200) fLineX2YV01(lin2,200)],'w-')    hold off    axis([-150 150 385 415])    cax = caxis;    caxis([-0.1*cax(2) 0.9*cax(2)])    set(gca,'fontsize',14);    elseif nargin==5 % static angle case           img = fImageRotV02(img,angle,[pvtXInd,pvtYInd]); % rotate image    xPrf = sum(img);    % integrate in y    for ii = 101:0.5*sizeX-1        rght = xPrf(ii+1:ii+0.5*sizeX); % right side        left = [fliplr(rght(ii+1:end)) xPrf(1:ii)];  % left side        rght = rght + fliplr(left); % symmetrize        rmsT(ii-100) = fGetRmsV01(1:0.5*sizeX,rght);    % rms of symmetrized profile    end    temp = xPrf + fliplr(xPrf); % symmetrize    rmsM = fGetRmsV01(1:0.5*sizeX,temp(1:0.5*sizeX));    xPrf = fliplr(xPrf);    % flip for other side    for ii = 101:0.5*sizeX-1        rght = xPrf(ii+1:ii+0.5*sizeX); % right side        left = [fliplr(rght(ii+1:end)) xPrf(1:ii)];  % left side        rght = rght + fliplr(left); % symmetrize        rmsT2(ii-100) = fGetRmsV01(1:0.5*sizeX,rght);    % rms of symmetrized profile    end    rmsAll = [rmsT rmsM fliplr(rmsT2)];    [~,minIdx] = min(rmsAll);    pvtXInd2 = minIdx + 100;    pvtYInd = pvtXInd2;    rotAngl = angle;    pvtT = interp1(1:sizeX,rawFrgT,pvtXInd2);        %% figure output    set(gca,'fontsize',14);    pcolor(rawFrgT,rawFrgL,img)    shading interp    colormap jet    hold on    plot([pvtT pvtT],[0 800],'w--')    plot([pvtT+50 pvtT+50],[0 800],'w--')    plot([pvtT-50 pvtT-50],[0 800],'w--')    plot([pvtT+100 pvtT+100],[0 800],'w--')    plot([pvtT-100 pvtT-100],[0 800],'w--')    plot([-200 200],[0.5*osPrp.lmb0 0.5*osPrp.lmb0],'w--')    plot([-200 200],[0.5*osPrp.lmb0+3 0.5*osPrp.lmb0+3],'w--')    plot([-200 200],[0.5*osPrp.lmb0-3 0.5*osPrp.lmb0-3],'w--')    plot([-200 200],[0.5*osPrp.lmb0+6 0.5*osPrp.lmb0+6],'w--')    plot([-200 200],[0.5*osPrp.lmb0-6 0.5*osPrp.lmb0-6],'w--')    hold off    %axis([-100 200 385 415])    axis([-150 150 385 415])    set(gca,'fontsize',14);else % static angle and offset case        img = rawImg;   % raw image    rotAngl = angle;    pvtT = varargin{1};    % pivot [fs]    [~,pvtXInd] = min(abs(rawFrgT - pvtT));   % pivot x pixel    img = fImageRotV02(img,angle,[pvtXInd,pvtYInd]); % rotate image        %% figure output    set(gca,'fontsize',14);    pcolor(rawFrgT,rawFrgL,img)    shading interp    colormap jet    hold on    plot([pvtT pvtT],[0 800],'w--')    plot([pvtT+50 pvtT+50],[0 800],'w--')    plot([pvtT-50 pvtT-50],[0 800],'w--')    plot([-200 200],[0.5*osPrp.lmb0 0.5*osPrp.lmb0],'w--')    plot([-200 200],[0.5*osPrp.lmb0+3 0.5*osPrp.lmb0+3],'w--')    plot([-200 200],[0.5*osPrp.lmb0-3 0.5*osPrp.lmb0-3],'w--')    plot([-200 200],[0.5*osPrp.lmb0+6 0.5*osPrp.lmb0+6],'w--')    plot([-200 200],[0.5*osPrp.lmb0-6 0.5*osPrp.lmb0-6],'w--')    hold off    axis([-150 150 385 415])    set(gca,'fontsize',14);end
